INSERT INTO public.products (id, name, description, short_description, price, images, material, layer_height, print_time, dimensions, stock, featured, category) VALUES
('a1b2c3d4-0001-4000-8000-000000000001', 'Geometric Vortex', 'A mesmerizing geometric sculpture featuring interlocking spirals that create an optical illusion of perpetual motion. Each layer is precisely calibrated at 0.1mm for maximum detail. Perfect as a desk centerpiece or conversation starter.', 'Interlocking spiral sculpture with optical illusion effect', 49.99, ARRAY['/product-1.jpg'], 'Resin', '0.05mm', '14 hours', '120 × 120 × 180mm', 12, true, 'Sculptures'),
('a1b2c3d4-0002-4000-8000-000000000002', 'Lattice Lamp Shade', 'An intricate lattice-pattern lamp shade that casts beautiful geometric shadow patterns across any room. Designed with parametric algorithms and printed in translucent PLA for a warm ambient glow.', 'Parametric lattice lamp shade with geometric shadow patterns', 79.99, ARRAY['/product-2.jpg'], 'PLA+', '0.1mm', '22 hours', '200 × 200 × 250mm', 8, true, 'Home Decor'),
('a1b2c3d4-0003-4000-8000-000000000003', 'Carbon Hex Coasters', 'Set of 4 hexagonal coasters printed in carbon fiber-infused filament. Each coaster features a honeycomb internal structure for lightweight strength and heat resistance up to 110°C.', 'Set of 4 carbon fiber hex coasters with honeycomb structure', 34.99, ARRAY['/product-3.jpg'], 'Carbon Fiber', '0.15mm', '6 hours', '100 × 87 × 8mm each', 25, false, 'Accessories'),
('a1b2c3d4-0004-4000-8000-000000000004', 'Fractal Dragon', 'A stunning dragon sculpture built using fractal geometry principles. The wings feature self-similar patterns at multiple scales, creating extraordinary detail visible from any distance.', 'Fractal geometry dragon with self-similar wing patterns', 129.99, ARRAY['/product-4.jpg'], 'Resin', '0.05mm', '36 hours', '180 × 250 × 200mm', 4, true, 'Sculptures'),
('a1b2c3d4-0005-4000-8000-000000000005', 'Modular Desk Organizer', 'A snap-together modular desk organizer system. Each module connects magnetically, allowing infinite configurations. Includes phone stand, pen holder, cable management, and card slot modules.', 'Magnetic modular desk organizer with 4 snap-together modules', 59.99, ARRAY['/product-5.jpg'], 'PLA+', '0.2mm', '18 hours', '300 × 150 × 120mm', 15, true, 'Accessories'),
('a1b2c3d4-0006-4000-8000-000000000006', 'Topographic Map Art', 'A layered topographic map art piece representing actual terrain data. Each contour layer is individually printed and assembled, creating a stunning 3D relief map perfect for wall mounting.', 'Layered 3D topographic terrain art for wall display', 89.99, ARRAY['/product-6.jpg'], 'PLA+', '0.1mm', '28 hours', '300 × 300 × 40mm', 6, false, 'Wall Art'),
('a1b2c3d4-0007-4000-8000-000000000007', 'Klein Bottle Vase', 'A mathematical impossibility made real — this Klein bottle-inspired vase features a surface with no distinguishable inside or outside. Watertight inner chamber holds fresh or dried flowers.', 'Mathematical Klein bottle vase with watertight chamber', 69.99, ARRAY['/product-7.jpg'], 'Resin', '0.05mm', '20 hours', '100 × 100 × 220mm', 10, false, 'Home Decor'),
('a1b2c3d4-0008-4000-8000-000000000008', 'Articulated Mech Hand', 'A fully articulated mechanical hand with 15 independent joints. Each finger moves naturally with cable-driven mechanics. An incredible display piece and conversation starter.', 'Fully articulated 15-joint mechanical hand sculpture', 149.99, ARRAY['/product-8.jpg'], 'PLA+', '0.1mm', '42 hours', '200 × 150 × 280mm', 3, true, 'Sculptures');
